// Read the Supabase Database Webhook payload.
// Works for EITHER trigger table:
//   notifications -> the order id is record.order_id, with record.type   (your flow)
//   orders        -> the order id is record.id, no record.type
const input = $input.first().json;
const body = input.body || input;
const rec = body.record || body;

const orderId = rec.order_id || rec.id || null;

// FILTER: only act on new orders. Notifications carry rec.type — we require
// 'new_order' so future notification types never trigger a call. The orders
// table has no 'type' column (rec.type is undefined) -> also allowed.
const proceed = !!orderId && (rec.type === 'new_order' || rec.type == null);

return [{ json: {
  eventType: body.type || '',
  notifType: rec.type || '',
  orderId,
  proceed
} }];

const raw = $('Fetch Order Details').first().json;
const order = Array.isArray(raw) ? raw[0] : (raw.body && Array.isArray(raw.body) ? raw.body[0] : raw);
if (!order || !order.id) { throw new Error('Order not found for orderId ' + $('Parse Notification').item.json.orderId); }

const rest = order.restaurants || {};
const placeName = [rest.name, rest.branch_name].filter(Boolean).join(' — ') || 'our restaurant';

// Normalize phone to E.164. Assumes India (+91) for 10-digit numbers — change if needed.
let phone = String(order.customer_phone || '').replace(/[^\d+]/g, '');
if (phone && !phone.startsWith('+')) {
  phone = phone.replace(/^0+/, '');
  phone = (phone.length === 10) ? '+91' + phone : '+' + phone;
}

const items = order.order_items || [];
const itemsSummary = items.map(it => {
  const name = it.variant_name ? (it.item_name + ' (' + it.variant_name + ')') : it.item_name;
  return it.quantity + 'x ' + name;
}).join(', ') || 'your items';

const claimRow = $('Claim Order (insert log)').first().json;
const logId = Array.isArray(claimRow) ? claimRow[0].id : claimRow.id;

return [{ json: {
  logId,
  orderId:       order.id,
  orderNumber:   order.order_number || '',
  customerName:  order.customer_name || 'there',
  customerPhone: phone,
  total:         order.total_amount,
  placeName,
  itemsSummary,
language: ((order.customers && order.customers.language) || 'English')

} }];

// Pull plain text out of Claude's response; fall back to a basic script.
const r = $input.first().json;
let text = '';
try { if (Array.isArray(r.content)) text = r.content.map(c => c.text || '').join(' ').trim(); } catch (e) {}
const ctx = $('Build Call Context').first().json;
const script = text || ('Hello ' + ctx.customerName + '. This is ' + ctx.placeName + '. Your order ' + ctx.orderNumber + ' for ' + ctx.itemsSummary + ' totalling ' + ctx.total + ' rupees has been placed successfully. Thank you!');
return [{ json: { script } }];

const raw = $input.first().json;
const arr = Array.isArray(raw) ? raw : (raw.body && Array.isArray(raw.body) ? raw.body : [raw]);
const row = arr[0] || {};
return [{ json: { script: row.script || 'Your order has been placed successfully. Thank you.' } }];

// Twilio reports the call result here; ?log_id was passed on StatusCallback URL.
const inp = $input.first().json;
const q = inp.query || {};
const b = inp.body || {};
const map = { 'completed': 'completed', 'no-answer': 'no_answer', 'busy': 'failed', 'failed': 'failed', 'canceled': 'canceled' };
const status = b.CallStatus || 'unknown';
return [{ json: {
  logId: q.log_id,
  callSid: b.CallSid || '',
  finalStatus: map[status] || status,
  pickedUp: status === 'completed'
} }];
